def prove_orim12dALT(sys: System) -> Proof:
    """Alternate proof of ~ orim12d which does not depend on ~ df-an .  This is
    an illustration of the conservativity of definitions (definitions do not
    permit to prove additional theorems whose statements do not contain the
    defined symbol).  (Contributed by Wolf Lammen, 8-Aug-2022.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "orim12dALT")
    h1 = lb.hyp("orim12dALT.1", "( φ → ( ψ → χ ) )")
    h2 = lb.hyp("orim12dALT.2", "( φ → ( θ → τ ) )")
    s1 = lb.ref("s1", "( ( ψ ∨ θ ) → ( ¬ ψ → θ ) )", ref="pm2.53", note="pm2.53")
    s2 = lb.ref("s2", "( φ → ( ¬ χ → ¬ ψ ) )", h1, ref="con3d", note="con3d")
    s3 = lb.ref("s3", "( φ → ( ( ¬ ψ → θ ) → ( ¬ χ → τ ) ) )", s2, h2, ref="imim12d", note="imim12d")
    s4 = lb.ref("s4", "( ( ¬ χ → τ ) → ( χ ∨ τ ) )", ref="pm2.54", note="pm2.54")
    res = lb.ref("res", "( φ → ( ( ψ ∨ θ ) → ( χ ∨ τ ) ) )", s1, s3, s4, ref="syl56", note="syl56")
    return lb.build(res)

def prove_orbi2i(sys: System) -> Proof:
    """Inference adding a left disjunct to both sides of a logical equivalence.
    (Contributed by NM, 3-Jan-1993.)  (Proof shortened by Wolf Lammen,
    12-Dec-2012.)
    """
    lb = ProofBuilder(sys, "orbi2i")
    h1 = lb.hyp("orbi2i.1", "( φ ↔ ψ )")
    s1 = lb.ref("s1", "( φ → ψ )", h1, ref="biimpi", note="biimpi")
    s2 = lb.ref("s2", "( ( χ ∨ φ ) → ( χ ∨ ψ ) )", s1, ref="orim2i", note="orim2i")
    s3 = lb.ref("s3", "( ψ → φ )", h1, ref="biimpri", note="biimpri")
    s4 = lb.ref("s4", "( ( χ ∨ ψ ) → ( χ ∨ φ ) )", s3, ref="orim2i", note="orim2i")
    res = lb.ref("res", "( ( χ ∨ φ ) ↔ ( χ ∨ ψ ) )", s2, s4, ref="impbii", note="impbii")
    return lb.build(res)

def prove_orbi1i(sys: System) -> Proof:
    """Inference adding a right disjunct to both sides of a logical
    equivalence.  (Contributed by NM, 3-Jan-1993.)
    """
    lb = ProofBuilder(sys, "orbi1i")
    h1 = lb.hyp("orbi2i.1", "( φ ↔ ψ )")
    s1 = lb.ref("s1", "( ( φ ∨ χ ) ↔ ( χ ∨ φ ) )", ref="orcom", note="orcom")
    s2 = lb.ref("s2", "( ( χ ∨ φ ) ↔ ( χ ∨ ψ ) )", h1, ref="orbi2i", note="orbi2i")
    s3 = lb.ref("s3", "( ( χ ∨ ψ ) ↔ ( ψ ∨ χ ) )", ref="orcom", note="orcom")
    res = lb.ref("res", "( ( φ ∨ χ ) ↔ ( ψ ∨ χ ) )", s1, s2, s3, ref="3bitri", note="3bitri")
    return lb.build(res)

def prove_orbi12i(sys: System) -> Proof:
    """Infer the disjunction of two equivalences.  (Contributed by NM,
    3-Jan-1993.)
    """
    lb = ProofBuilder(sys, "orbi12i")
    h1 = lb.hyp("orbi12i.1", "( φ ↔ ψ )")
    h2 = lb.hyp("orbi12i.2", "( χ ↔ θ )")
    s1 = lb.ref("s1", "( ( φ ∨ χ ) ↔ ( φ ∨ θ ) )", h2, ref="orbi2i", note="orbi2i")
    s2 = lb.ref("s2", "( ( φ ∨ θ ) ↔ ( ψ ∨ θ ) )", h1, ref="orbi1i", note="orbi1i")
    res = lb.ref("res", "( ( φ ∨ χ ) ↔ ( ψ ∨ θ ) )", s1, s2, ref="bitri", note="bitri")
    return lb.build(res)

def prove_orbi2d(sys: System) -> Proof:
    """Deduction adding a left disjunct to both sides of a logical equivalence.
    (Contributed by NM, 21-Jun-1993.)
    """
    lb = ProofBuilder(sys, "orbi2d")
    h1 = lb.hyp("bid.1", "( φ → ( ψ ↔ χ ) )")
