    s3 = lb.ref("s3", "( ( χ ∨ ψ ) ↔ ( ψ ∨ χ ) )", ref="orcom", note="orcom")
    s4 = lb.ref("s4", "( ( φ ∨ ( χ ∨ ψ ) ) ↔ ( φ ∨ ( ψ ∨ χ ) ) )", s3, ref="orbi2i", note="orbi2i")
    res = lb.ref("res", "( ( ( φ ∨ ψ ) ∨ χ ) ↔ ( φ ∨ ( ψ ∨ χ ) ) )", s1, s2, s4, ref="3bitri", note="3bitri")
    return lb.build(res)

