def prove_pm2_81(sys: System) -> Proof:
    """Theorem *2.81 of [WhiteheadRussell] p. 108.  (Contributed by NM,
    3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm2.81")
    s1 = lb.ref("s1", "( ( ψ → ( χ → θ ) ) → ( ( φ ∨ ψ ) → ( φ ∨ ( χ → θ ) ) ) )", ref="orim2", note="orim2")
    s2 = lb.ref("s2", "( ( φ ∨ ( χ → θ ) ) → ( ( φ ∨ χ ) → ( φ ∨ θ ) ) )", ref="pm2.76", note="pm2.76")
    res = lb.ref("res", "( ( ψ → ( χ → θ ) ) → ( ( φ ∨ ψ ) → ( ( φ ∨ χ ) → ( φ ∨ θ ) ) ) )", s1, s2, ref="syl6", note="syl6")
    return lb.build(res)

def prove_pm2_8(sys: System) -> Proof:
    """Theorem *2.8 of [WhiteheadRussell] p. 108.  (Contributed by NM,
    3-Jan-2005.)  (Proof shortened by Wolf Lammen, 5-Jan-2013.)
    """
    lb = ProofBuilder(sys, "pm2.8")
    s1 = lb.ref("s1", "( ( φ ∨ ψ ) → ( ¬ φ → ψ ) )", ref="pm2.53", note="pm2.53")
    s2 = lb.ref("s2", "( ( φ ∨ ψ ) → ( ¬ ψ → φ ) )", s1, ref="con1d", note="con1d")
    res = lb.ref("res", "( ( φ ∨ ψ ) → ( ( ¬ ψ ∨ χ ) → ( φ ∨ χ ) ) )", s2, ref="orim1d", note="orim1d")
    return lb.build(res)

def prove_pm2_73(sys: System) -> Proof:
    """Theorem *2.73 of [WhiteheadRussell] p. 108.  (Contributed by NM,
    3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm2.73")
    s1 = lb.ref("s1", "( ( φ → ψ ) → ( ( φ ∨ ψ ) → ψ ) )", ref="pm2.621", note="pm2.621")
    res = lb.ref("res", "( ( φ → ψ ) → ( ( ( φ ∨ ψ ) ∨ χ ) → ( ψ ∨ χ ) ) )", s1, ref="orim1d", note="orim1d")
    return lb.build(res)

def prove_pm2_74(sys: System) -> Proof:
    """Theorem *2.74 of [WhiteheadRussell] p. 108.  (Contributed by NM,
    3-Jan-2005.)  (Proof shortened by Andrew Salmon, 7-May-2011.)
    """
    lb = ProofBuilder(sys, "pm2.74")
    s1 = lb.ref("s1", "( ¬ ψ → ( ( φ ∨ ψ ) → φ ) )", ref="orel2", note="orel2")
    s2 = lb.ref("s2", "( φ → ( ( φ ∨ ψ ) → φ ) )", ref="ax-1", note="ax-1")
    s3 = lb.ref("s3", "( ( ψ → φ ) → ( ( φ ∨ ψ ) → φ ) )", s1, s2, ref="ja", note="ja")
    res = lb.ref("res", "( ( ψ → φ ) → ( ( ( φ ∨ ψ ) ∨ χ ) → ( φ ∨ χ ) ) )", s3, ref="orim1d", note="orim1d")
    return lb.build(res)

def prove_pm2_82(sys: System) -> Proof:
    """Theorem *2.82 of [WhiteheadRussell] p. 108.  (Contributed by NM,
    3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm2.82")
    s1 = lb.ref("s1", "( χ → ( ¬ χ → ψ ) )", ref="pm2.24", note="pm2.24")
    s2 = lb.ref("s2", "( χ → ( ( φ ∨ ¬ χ ) → ( φ ∨ ψ ) ) )", s1, ref="orim2d", note="orim2d")
    s3 = lb.ref("s3", "( ( ( φ ∨ ψ ) ∨ χ ) → ( ( φ ∨ ¬ χ ) → ( φ ∨ ψ ) ) )", s2, ref="jao1i", note="jao1i")
    res = lb.ref("res", "( ( ( φ ∨ ψ ) ∨ χ ) → ( ( ( φ ∨ ¬ χ ) ∨ θ ) → ( ( φ ∨ ψ ) ∨ θ ) ) )", s3, ref="orim1d", note="orim1d")
    return lb.build(res)

def prove_pm4_39(sys: System) -> Proof:
    """Theorem *4.39 of [WhiteheadRussell] p. 118.  (Contributed by NM,
    3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm4.39")
    s1 = lb.ref("s1", "( ( ( φ ↔ χ ) ∧ ( ψ ↔ θ ) ) → ( φ ↔ χ ) )", ref="simpl", note="simpl")
    s2 = lb.ref("s2", "( ( ( φ ↔ χ ) ∧ ( ψ ↔ θ ) ) → ( ψ ↔ θ ) )", ref="simpr", note="simpr")
    res = lb.ref("res", "( ( ( φ ↔ χ ) ∧ ( ψ ↔ θ ) ) → ( ( φ ∨ ψ ) ↔ ( χ ∨ θ ) ) )", s1, s2, ref="orbi12d", note="orbi12d")
    return lb.build(res)

def prove_animorl(sys: System) -> Proof:
    """Conjunction implies disjunction with one common formula (1/4).
    (Contributed by BJ, 4-Oct-2019.)
    """
    lb = ProofBuilder(sys, "animorl")
