    s3 = lb.ref("s3", "( ( φ ∧ ψ ) → φ )", ref="simpl", note="simpl")
    s4 = lb.ref("s4", "( ( φ ∨ ( φ ∧ ψ ) ) → φ )", s2, s3, ref="jaoi", note="jaoi")
    res = lb.ref("res", "( φ ↔ ( φ ∨ ( φ ∧ ψ ) ) )", s1, s4, ref="impbii", note="impbii")
